import { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { useMutation } from '@tanstack/react-query';
import { z } from 'zod';
import { Loader2 } from 'lucide-react';
import { authService as accountService } from '@/api/auth/authService';
import { getApiErrorMessage, getApiErrorStatus } from '@/api/app/apiError';

import { AuthLayout } from '../layouts/AuthLayout';
import { HarmonyInput } from '@/components/ui/harmony-input';
import { Button } from '@/shadcn/components/ui/button';
import { Alert, AlertDescription } from '@/shadcn/components/ui/alert';

const forgotSchema = z.object({
  email: z.string().min(1, 'Email is required').email('Invalid email address').trim(),
});

type ForgotFormData = z.infer<typeof forgotSchema>;

export default function ForgotPassword() {
  const navigate = useNavigate();
  const [isSubmitted, setIsSubmitted] = useState(false);
  const [serverError, setServerError] = useState<string | null>(null);

  const { register, handleSubmit, formState: { errors } } = useForm<ForgotFormData>({
    resolver: zodResolver(forgotSchema),
  });

  const mutation = useMutation({
    mutationFn: (data: ForgotFormData) =>
      accountService.forgotPassword(data.email),

    onSuccess: () => {
      setIsSubmitted(true);

      setTimeout(() => {
        navigate('/login');
      }, 3000);
    },

    onError: (error) => {
      if (getApiErrorStatus(error) === 404) {
        setServerError("The user does not exist.");
      } else {
        setServerError(getApiErrorMessage(error));
      }
    },
  });

  return (
    <AuthLayout>
      <div className="bg-card rounded-xl shadow-xl p-8 border border-border">
        {!isSubmitted ? (
          <>
            <h2 className="text-xl font-semibold text-foreground mb-6">
              Forgot Password
            </h2>

            {serverError && (
              <Alert variant="destructive" className="mb-4">
                <AlertDescription>{serverError}</AlertDescription>
              </Alert>
            )}

            <form onSubmit={handleSubmit((data) => { setServerError(null); mutation.mutate(data); })} className="space-y-5">
              <HarmonyInput
                label="Email Address"
                type="email"
                placeholder="Enter your registered email"
                error={errors.email?.message}
                {...register('email')}
              />

              <Button type="submit" className="w-full" disabled={mutation.isPending}>
                {mutation.isPending && <Loader2 className="animate-spin" />}
                Send Reset Token
              </Button>
            </form>
          </>
        ) : (
          <div className="text-center py-6 animate-in fade-in zoom-in duration-300">
             <div className="w-16 h-16 bg-emerald-100 dark:bg-emerald-950/40 rounded-full flex items-center justify-center mx-auto mb-4">
              <svg className="w-8 h-8 text-emerald-600 dark:text-emerald-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7" />
              </svg>
            </div>
            <h2 className="text-xl font-semibold text-foreground mb-2">Email Sent!</h2>
            <p className="text-muted-foreground text-sm mb-6">
              Check your inbox for password reset instructions.
            </p>
            <p className="text-[10px] text-muted-foreground uppercase tracking-widest">Redirecting to login...</p>
          </div>
        )}

        <div className="mt-6 text-center pt-6 border-t border-border">
          <Link to="/login" className="text-sm text-primary hover:text-primary/80 font-medium">
            Back to Sign In
          </Link>
        </div>
      </div>
    </AuthLayout>
  );
}
